func main() {
	start := time.Now()
	//var nums []int = []int{3, 1, 4, 7, 2, 1, 4, 35, 6}
	//fmt.Printf("Unsorted: %v\n", nums)
	bubbleSort(L1)
	//fmt.Printf("Sorted: %v\n", nums)
	fmt.Println(time.Since(start))
}

func bubbleSort(nums []int) {
	for i := 0; i < len(nums); i++ {
		sweep(nums)
	}
}

func sweep(nums []int) {

	var firstIndex, secondIndex int = 0, 1

	for secondIndex < len(nums) {
		var firstNum = nums[firstIndex]
		var secondNum = nums[secondIndex]

		if firstNum > secondNum {
			nums[firstIndex] = secondNum
			nums[secondIndex] = firstNum
		}

		firstIndex++
		secondIndex++
	}

}
